	"context"
	"testing"

	"github.com/stretchr/testify/require"

	"github.com/cilium/cilium/pkg/identity"
	"github.com/cilium/cilium/pkg/policy/api"
)

func TestNewPolicyAuditLogger(t *testing.T) {
	logger := NewPolicyAuditLogger()
	require.NotNil(t, logger)
}

func TestPolicyAuditLoggerLogDecision(t *testing.T) {
	logger := NewPolicyAuditLogger()

	testID := identity.NumericIdentity(123)
	policy := "test-policy"
	verdict := api.Allowed
	reason := "matched rule"

	// Should not panic
	logger.LogDecision(testID, policy, verdict, reason)
}

func TestPolicyAuditLoggerLogEvaluationWithoutCache(t *testing.T) {
	logger := NewPolicyAuditLogger()

	policyKey := "test-key"
	result := api.Allowed
	ctx := context.Background()

	// Should not panic with nil selector cache
	logger.LogEvaluation(ctx, policyKey, nil, result)
}

func TestPolicyAuditLoggerLogEvaluationWithCache(t *testing.T) {
	logger := NewPolicyAuditLogger()

	policyKey := "test-key-with-cache"
	result := api.Denied
	ctx := context.Background()

	repo := NewRepository()
	selectorCache := repo.GetSelectorCache()

	// Should not panic with selector cache
	logger.LogEvaluation(ctx, policyKey, selectorCache, result)
}

func TestPolicyAuditLoggerConcurrentCalls(t *testing.T) {
	logger := NewPolicyAuditLogger()

	testID := identity.NumericIdentity(456)
	policy := "concurrent-policy"

	// Run concurrent operations to verify thread safety
	done := make(chan bool, 2)

	go func() {
		for i := 0; i < 100; i++ {
			logger.LogDecision(testID, policy, api.Allowed, "concurrent call")
		}
		done <- true
	}()

	go func() {
		for i := 0; i < 100; i++ {
			logger.LogEvaluation(context.Background(), "concurrent-key", nil, api.Denied)
		}
		done <- true
	}()

	<-done
	<-done
}

func TestPolicyAuditLoggerVerdicts(t *testing.T) {
	logger := NewPolicyAuditLogger()

	testID := identity.NumericIdentity(999)
	policy := "verdict-test"

	verdicts := []api.Decision{
		api.Undecided,
		api.Allowed,
		api.Denied,
	}

	for _, verdict := range verdicts {
		logger.LogDecision(testID, policy, verdict, "testing verdict")
	}
}

